#!/usr/bin/env python3
from datetime import datetime
from pathlib import Path
import base64
import shutil
import sys

ROOT = Path.cwd()
ROUTE = ROOT / "src/app/api/sectors/route.ts"

if not ROUTE.exists():
    print("خطأ: شغّل الملف من داخل مجلد apps/web")
    sys.exit(1)

stamp = datetime.now().strftime("%Y%m%d-%H%M%S")
backup = Path("/tmp") / f"sector-before-final-source-fix-{stamp}.ts"
shutil.copy2(ROUTE, backup)

ROUTE.write_bytes(
    base64.b64decode(
        ''
    )
)

print("تم تطبيق المصدر الصحيح للقطاعات والشركات.")
print("- Finnhub: السعر الحالي فقط")
print("- Massive: الإغلاق السابق، أداء 5 جلسات، الحجم، القوة والسيولة")
print("- ثلاثة طلبات Massive مجمعة فقط بدل طلب لكل رمز")
print("- الشركات والقطاعات تستخدم نفس بيانات Massive المحفوظة")
print(f"النسخة الاحتياطية: {backup}")
print("الخطوة التالية: npm run build")
